var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>레. 지나. 왜. 여. 기 있. 어.</color>","JPN":"<color=#ff3636>レ、ジーナ。ドウシ、テコ、コニイ、ル。</color>","ENG":"<color=#ff3636>Re. Gina. Why. Are you. Here?</color>","TWN":"<color=#ff3636>蕾·佳娜·為什麼·在·這·裡。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희들을 얼릴 수 있다, 라……?","JPN":"我々を凍らせる、と……？","ENG":"I-it's freezing us...?","TWN":"可以凍結我們，嗎……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"후훗, 평범한 냉기는 아니네요. 재미있는 메뉴예요.","JPN":"ふふっ、普通の冷気ではありませんね。面白いメニューです。","ENG":"Hah hah. That seems like no ordinary frost. What an interesting menu we have.","TWN":"呵呵，不是普通的寒氣呢。這道菜很有趣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"세라펠과 합중국, 양측에 대부분의 힘을 분할했다고 해도… 이 정도 분전은 기대 이상이에요.","JPN":"セラフェルと合衆国、両側にほとんどの力を分割しているとはいえ……これほどの奮戦は期待以上です。","ENG":"Despite dividing the majority of our forces between Serapel and the States... You have exceeded our expectations.","TWN":"就算我們分出了大部分力量干擾塞拉費爾和合眾國……你能有這種表現，也超出我們的期待了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하지만 그렇다고 해서 당신에게 레지나 님을 넘겨드릴 수는 없답니다.","JPN":"でも、だからといってあなたにレジーナ様をお渡しすることはできません。","ENG":"Nevertheless, we will not be handing Miss Regina over to you.","TWN":"不過即便如此，我們也不能把蕾佳娜交給你。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"윽……. 부딪치는 여파만으로도 몸이 휘청거릴 정도네.","JPN":"うっ……ぶつかる余波だけでも体がふらつくわ。","ENG":"Ngh... The impact alone is enough to knock me down.","TWN":"呃……光是碰撞的餘波，就讓人站不穩了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"처음 보는 괴물인데 뭐 하는 녀석이람? 마왕에게 힘으로 덤빈다고?","JPN":"初めて見る怪物だけど、何者かしら。魔王に力勝負を挑むなんて。","ENG":"I've never seen this monster before. What exactly is it? Is it using brute force to defeat a Demon Lord?","TWN":"我第一次看到這種怪物，它是什麼東西？竟敢憑蠻力撲向魔王？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"어쩌실래요, 지휘자님? 저희도 가세할까요?","JPN":"どうされますか？　マエストロ。私たちも加勢しましょうか？","ENG":"What shall we do, Chief Conductor? Should we help them?","TWN":"怎麼辦，指揮家？我們也要加入嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"속단하지 마세요, 카르멘. 저희가 맺은 계약은 어디까지나 의식을 돕는 것뿐입니다.","JPN":"速断は禁物です、カルメン。私たちの契約はあくまでも儀式を手伝うことだけです。","ENG":"Do not jump to conclusions, Carmen. We only agreed to assist with the ritual.","TWN":"別輕易下結論，卡門。我們的約定只是幫助完成儀式。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"상황을 충분히 지켜본 뒤 가세해도 늦지 않아요.","JPN":"十分状況を見守ってから加勢しても遅くありません。","ENG":"It will not be too late to help after observing the situation.","TWN":"充分觀察情況後再加入也不遲。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"만에 하나의 가능성이지만, 설령 가아그셰블라께서 고전을 면치 못하셔도……","JPN":"万が一の可能性ですが、たとえガアグシェブラが苦戦を免れなくても……","ENG":"But in the one-in-a-million chance that Gha'agsheblah falters...","TWN":"雖然可能性很小，但萬一加瓦格夫拉陷入苦戰……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"저희는 저희대로 합리적인 결정을 내리면 그만이죠. 늘 그랬듯이.","JPN":"私たちは私たちなりの合理的な判断を下せばいいのです。いつもどおりに。","ENG":"We will simply make our decision based on reason, as we have always done.","TWN":"到時候我們再做出合理的決定就行了，就像一直以來那樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"역시 그렇죠? 지휘자님다운 판단이네요.","JPN":"やはりそうですよね？　マエストロらしい判断です。","ENG":"You're right. Good call, Chief Conductor.","TWN":"果然是這種判斷吧？很符合指揮家的風格。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 정신 차리세요!","JPN":"副学会長様、しっかりしてください！","ENG":"Ms. Vice President! Please wake up!","TWN":"副學會長，你醒醒！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"저 괴물이 부학회장님을 찾고 있어요. 어서 여기서 도망치셔야 해요.","JPN":"あの怪物が副学会長様を探しています。早くここから逃げないといけません。","ENG":"That monster's looking for you. You must get out of here.","TWN":"那個怪物在找副學會長，你必須快點離開這裡。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저는…….","JPN":"私は……","ENG":"There is...","TWN":"我……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저는 아무것도 할 수 없어요. 제가 어떻게……","JPN":"私は何もできませんわ。私にはそんな……","ENG":"There is nothing I can do. How can I...","TWN":"我什麼都做不了，怎麼能……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어떻, 게…… 저 한 명 때문에…… 전 아무것도 모르는 바보일 뿐인데……","JPN":"そん、な……私一人のために……私は何も知らないバカでした……","ENG":"H-how can... All because of me...? I am just a foolish–","TWN":"怎麼…能……因為我一個人……我就是個什麼都不知道的傻瓜……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맥크레디 양, 외면하지 말게. 체념하기엔 아직 일러.","JPN":"マクレディー君、目を背けてはいけない。諦めるにはまだ早いぞ。","ENG":"Regina, no. It's too early to give up.","TWN":"麥克蕾蒂，別逃避，現在就心灰意冷還早了點。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"조, 조금만 참으세요. 제가 금방 촉수를 풀어 드릴게요.","JPN":"も、もう少しだけ我慢してください。私がすぐに触手をほどきますから。","ENG":"J-just hang in there a little longer. I'll set you free from those tentacles...!","TWN":"你再…再堅持一下，我馬上給你鬆開觸手。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"에잇……! 에이잇……!","JPN":"えいっ……！　ええいっ……！","ENG":"Hmph...! Eeek...!","TWN":"哎呀……！唉呀呀……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……소용없어요. 에델의 촉수를 힘으로 끊는 건 불가능해요.","JPN":"……無駄ですわ。エデルの触手を力でちぎることは不可能です。","ENG":"...It is useless. It is impossible to physically sever Edel's tentacles.","TWN":"……沒用的，艾瑟兒的觸手沒辦法用力量斬斷。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사장님을 데리고 도망쳐요. 간병인이라고 여기서 계속 우물쭈물하다간 죽을 거예요.","JPN":"社長を連れて逃げなさい。看病人だからってずっとここでぐずぐずしていては殺されてしまいます。","ENG":"Take Boss and run. If you stay here, you will die as well.","TWN":"帶著老闆逃走吧。如果你堅持作為看護留在這裡，你會死的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"하지만……! 하지만……!","JPN":"でも……！　でも……！","ENG":"But...! BUT...!","TWN":"但是……！但是……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"잠깐 실례!","JPN":"ちょっと失礼！","ENG":"Scuse me!","TWN":"失禮了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"꺄악!?","JPN":"きゃあっ！？","ENG":"Eeek!","TWN":"啊啊！？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님을 붙잡고 있던 파편들이 조용해졌어……?","JPN":"レジーナ様を捕まえていた破片が大人しくなった……？","ENG":"The Fragments that were holding Miss Regina... They've gone silent...?","TWN":"抓住蕾佳娜的碎片都安靜下來了……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"리벳! 당신인가요!","JPN":"リベット！　あなたですか！","ENG":"Rivet! Is this your doing?!","TWN":"里維！是你嗎！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아차, 시무룩한 레지나를 보니 나도 모르게 그만!","JPN":"しまった、落ち込んでるレジーナを見て、つい！","ENG":"Oops! But I couldn't help myself after seeing Regina's glum expression.","TWN":"哎呀，看到蕾佳娜不高興，我下意識地就動手了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"하지만 기왕 이렇게 된 거 레지나는 내가 챙겨 갈게, 에델!","JPN":"でもこうなったからには、レジーナはアタシが連れていくね、エデル！","ENG":"Well, since this already happened, I'll just take Regina! Okay, Edel?","TWN":"不過事已至此，蕾佳娜我就帶走了，艾瑟兒！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"멈추세요! 레지나 님은 그 상태로 오래 사실 수 없어요!","JPN":"待ちなさい！　レジーナ様はその状態では長く生きられません！","ENG":"Stop! She won't last long in that state!","TWN":"住手！蕾佳娜那個狀態，是活不了多久的！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"나도 교통 카드 반 조각으로 일하기 지쳤거든! 레지나를 되찾고 싶다면 나머지 반 장을 요구한다!","JPN":"アタシもプリペイドカードの半分の額で働くのはもうこりごりだよ！　レジーナを取り戻したかったら、残りの半分を要求する！","ENG":"You know, I'm tired of working for just half of a prepaid transportation card! If you want Regina back, I demand the other half too!","TWN":"我受夠只能報銷一半交通費就替你賣命的日子了！如果想帶回蕾佳娜，就給我報銷剩下的！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아 참, 얘도 슬쩍~","JPN":"あ、そうだ。この子もちょこ～っと。","ENG":"Oh, I'll take her too!","TWN":"啊，對了，這孩子也～"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"내, 내려 주세요! 저도 뛸 수 있어요!","JPN":"お、下ろしてください！　私も走れます！","ENG":"P-put me down! I can run by myself!","TWN":"放…放我下來！我也能跑！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저에게서 도망칠 수 있다고 생각하셨다면……! 읏?!","JPN":"我々から逃げられると思ったのなら……！　うっ！？","ENG":"If you think you can run away from m–! Ngh?!","TWN":"如果你以為能逃出我們的手掌心……！呃？！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>레지. 나아아아아아아아!!</color>","JPN":"<color=#ff3636>レジー、ナアアアアアアア！！</color>","ENG":"<color=#ff3636>REGI. NAAAAAA!!</color>","TWN":"<color=#ff3636>蕾佳·娜·啊啊啊啊啊啊！！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_21"},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희들의 구상을 망치다니……","JPN":"我々の構想を台無しにするとは……","ENG":"How dare you ruin our plans...","TWN":"竟然毀掉我們的構想……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하이드리히! 공간의 균열로 뛰어들 작정이에요! 막으세요!","JPN":"ハイドリヒ！　空間の亀裂に飛び込むつもりです！　止めなさい！","ENG":"Heydrich! They are planning on running into the rift! Stop them!","TWN":"海德里希！她們想跳進空間裂縫！攔住她們！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"알겠습니다, 학회장님.","JPN":"承知した、学会長。","ENG":"Yes, ma'am.","TWN":"知道了，學會長。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"의식이 끝날 때까지 부학회장님은 살려 둬야 한다! 전원, 저 외지인의 다리를 노려라!","JPN":"儀式が終わるまで、副学会長は生かしておかなければならない！　全員、あのよそ者の足を狙え！","ENG":"Ms. Vice President must be alive until the ritual is over! All hands aim for the outlander's legs!","TWN":"在儀式結束之前，副學會長必須活著！全體人員，瞄準那個外地人的腿！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"레지나! 촉수 괴물로 살 바에야 역시 도박을 거는 편이 낫지?","JPN":"レジーナ！　触手の化け物として生きるよりは、やっぱり賭けをした方がいいよね？","ENG":"Regina! You'd rather take a gamble than become a tentacle monster, right?","TWN":"蕾佳娜！與其作為觸手怪物活著，不如乾脆賭一把吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"대답은 안 해도 돼! 난 언제나 내 고용주랑 이심전심이었거든!","JPN":"答えなくていい！　アタシはいつもクライアントと以心伝心だったから！","ENG":"You don't have to answer! I always know what my clients are thinking!","TWN":"你不用回答！因為我總是跟雇主心有靈犀！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"저 미친 계집이? 설마 정말 저지를 속셈인가?","JPN":"あの小娘、正気なのか？　まさか本当にやるつもりか？","ENG":"That crazy girl... Is she really thinking of jumping in there?","TWN":"那個瘋丫頭？不會真打算這麼做吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"아무리 안정된 상태여도 차원의 틈을 비집고 들어가는 짓이다!","JPN":"いくら安定した状態とは言え、次元の隙間をこじ開けることになるんだぞ！","ENG":"Regardless of its stability, you are squeezing through a dimensional crack!","TWN":"不管狀態多麼穩定，那也是進入次元裂縫！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"부학회장까지 죽일 작정이냐, 네 년은!!","JPN":"副学会長まで殺す気か、貴様は！！","ENG":"You're going to kill her!!","TWN":"你這個臭丫頭，是打算殺死副學會長嗎！！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이거 곤란하군……. 저 자가 구구절절 맞는 말만 하고 있어.","JPN":"これは困ったな……あの者の言葉はもっともなことばかりだ。","ENG":"Well, this is troubling... What he's saying is all correct.","TWN":"這下麻煩了……那個人說的每一句話都是對的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"여, 역시 다른 길을 찾는 편이 낫지 않을까요? 부학회장님께서 돌아가시면 저는……!","JPN":"や、やっぱり他の道を探した方がいいんじゃないですか？　副学会長様がお亡くなりになったら私は……！","ENG":"W-wouldn't it be better to find another way?! If the Vice President dies, then I'll...!","TWN":"還…還是找找別的路更好吧？副學會長死掉的話，我……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"앗, 어떡해! 저 말 들으니까 더 뛰어들고 싶어졌어!","JPN":"あっ、どうしよう！　あれ聞いたらもっと飛び込みたくなっちゃった！","ENG":"Oh, geez! Hearing that just makes me want to jump in even more!","TWN":"啊，怎麼辦！聽完那些話，我更想跳進去了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"꽉 잡아, 다들!","JPN":"みんな、ちゃんと掴まっててね！","ENG":"Hang on tight, y'all!","TWN":"都抓緊了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"꺄아아아아아!!","JPN":"きゃあああああ！！","ENG":"KYAAAAH!!","TWN":"噶啊啊啊啊啊！！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND"}]`);export{e as default};